using Microsoft.EntityFrameworkCore;

// Cosmos DB provider — EF Core 9 breaking changes addressed below.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1 — Discriminator property renamed.
        // EF Core 9 changed the default discriminator from "Discriminator" to "$type".
        // Existing documents already store "Discriminator", so we must keep the old name
        // to avoid a mismatch that silently returns zero results.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }

    // BREAKING CHANGE 2 — Synchronous Cosmos DB I/O removed.
    // The Cosmos DB provider in EF Core 9 no longer supports synchronous queries;
    // calling .ToList(), .First(), .Single(), etc. throws InvalidOperationException.
    // All queries must use their async counterparts.

    // ❌ BEFORE (EF Core 8 — synchronous, now throws in EF Core 9):
    //   var products = db.Products.Where(p => p.Price > 10).ToList();

    // ✅ AFTER (EF Core 9 — async):
    //   var products = await db.Products.Where(p => p.Price > 10).ToListAsync();
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public decimal Price { get; set; }
}

